// // This comment suggests that the register will only update when the clear signal is active.
module register_8bit(
    input clk,
    input clr,
    input load,
    input [7:0] d,

    output reg [7:0] q
);
    always @(posedge clk or posedge clr) begin
        if (clr) 
            q <= 8'b00000000;
        else if (load) 
            q <= d;
    end
endmodule
